import{_ as a,c as e,o as t,b as m}from"./app.2f23aa5c.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 9","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 9","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-02T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/9/index.md"}',p={},i=m('<div class="stanza"><a href="#s2.9" id="s2.9" class="num">2.9</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u091A\u2014</p><blockquote><p><strong>\u091C\u094D\u091E\u093E\u0928\u092E\u0928\u094D\u0928\u092E\u094D\u0965\u096F\u0965</strong></p></blockquote><p>\u092F\u0924\u094D\u092A\u0942\u0930\u094D\u0935\u0902 \u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0928\u094D\u0927\u0903 (\u0967-\u0968) \u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0902 \u0924\u0926\u0926\u094D\u092F\u092E\u093E\u0928\u0924\u094D\u0935\u093E\u0926\u094D\u0917\u094D\u0930\u0938\u094D\u092F\u092E\u093E\u0928\u0924\u094D\u0935\u093E\u0926\u094D\u092F\u094B\u0917\u093F\u0928\u093E\u092E\u0928\u094D\u0928\u092E\u094D\u0964 \u092F\u0924\u094D\u0938\u0902\u0935\u093E\u0926\u093F\u0924\u0902 \u092A\u094D\u0930\u093E\u0915\u094D</p><blockquote><p>\u092E\u0943\u0924\u094D\u092F\u0941\u0902 \u091A \u0915\u093E\u0932\u0902 \u091A \u0915\u0932\u093E\u0915\u0932\u093E\u092A\u0902 \u0935\u093F\u0915\u093E\u0930\u091C\u093E\u0932\u0902 \u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0938\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u094D\u0964<br> \u0910\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u0928\u093E\u0928\u093E\u0924\u094D\u092E\u094D\u092F\u0935\u093F\u0924\u0930\u094D\u0915\u091C\u093E\u0924\u0902 \u0924\u0926\u093E \u0938 \u0938\u0930\u094D\u0935\u0902 \u0915\u0935\u0932\u0940\u0915\u0930\u094B\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964</p><p>\u0905\u0925 \u091A \u092F\u0924\u094D\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0924\u094D\u092E\u0915\u0902 \u091C\u094D\u091E\u093E\u0928\u0902 \u0924\u0926\u0938\u094D\u092F\u093E\u0928\u094D\u0928\u0902 \u092A\u0942\u0930\u094D\u0923\u092A\u0930\u093F\u0924\u0943\u092A\u094D\u0924\u093F\u0915\u093E\u0930\u093F\u0924\u092F\u093E \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0939\u0947\u0924\u0941\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0905\u0924\u094D\u0930\u0948\u0915\u0924\u092E\u092F\u0941\u0915\u094D\u0924\u093F\u0938\u094D\u0925\u0947 \u092F\u094B\u0924\u094D\u092A\u0926\u094D\u092F\u0924\u0947 \u0926\u093F\u0928\u093E\u0926\u094D\u0926\u093F\u0928\u092E\u094D\u0964<br> \u092D\u0930\u093F\u0924\u093E\u0915\u093E\u0930\u093F\u0924\u093E \u0938\u093E\u0924\u094D\u0930 \u0924\u0943\u092A\u094D\u0924\u093F\u0930\u0924\u094D\u092F\u0928\u094D\u0924\u092A\u0942\u0930\u094D\u0923\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092F\u0941\u0915\u094D\u0924\u093F\u0930\u094D\u0939\u093F \u0924\u0924\u094D\u0930 \u0926\u094D\u0935\u093E\u0926\u0936\u094B\u0924\u094D\u0924\u0930\u0936\u0924\u092D\u0942\u092E\u093F\u0915\u093E\u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u0948\u0935\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u094D\u092A\u0928\u094D\u0926\u0947</p><blockquote><p>\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0903 \u0938\u0930\u094D\u0935\u0926\u093E \u0924\u093F\u0937\u094D\u0920\u0947\u0924\u094D...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u092F\u093E \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u096F\u0965</p></div><hr><div class="trans"><p>Asya ca\u2014</p><blockquote><p><strong>J\xF1\u0101namannam||9||</strong></p></blockquote><p>Yatp\u016Brva\u1E41 j\xF1\u0101na\u1E41 bandha\u1E25 (1-2) ityukta\u1E41 tadadyam\u0101natv\u0101dgrasyam\u0101natv\u0101dyogin\u0101mannam| Yatsa\u1E41v\u0101dita\u1E41 pr\u0101k</p><blockquote><p>M\u1E5Btyu\u1E41 ca k\u0101la\u1E41 ca kal\u0101kal\u0101pa\u1E41 vik\u0101raj\u0101la\u1E41 pratipattis\u0101tmyam|<br> Aik\u0101tmyan\u0101n\u0101tmyavitarkaj\u0101ta\u1E41 tad\u0101 sa sarva\u1E41 kaval\u012Bkaroti||</p></blockquote><p>iti|</p><p>Atha ca yatsvar\u016Bpavimar\u015B\u0101tmaka\u1E41 j\xF1\u0101na\u1E41 tadasy\u0101nna\u1E41 p\u016Br\u1E47aparit\u1E5Bptik\u0101ritay\u0101 sv\u0101tmavi\u015Br\u0101ntihetu\u1E25| Tadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Atraikatamayuktisthe yotpadyate din\u0101ddinam|<br> Bharit\u0101k\u0101rit\u0101 s\u0101tra t\u1E5Bptiratyantap\u016Br\u1E47at\u0101||</p></blockquote><p>iti| Yuktirhi tatra dv\u0101da\u015Bottara\u015Batabh\u016Bmik\u0101j\xF1\u0101nar\u016Bpaiva| Etacca spande</p><blockquote><p>Prabuddha\u1E25 sarvad\u0101 ti\u1E63\u1E6Dhet...|</p></blockquote><p>ityanay\u0101 k\u0101rikay\u0101 sa\u1E45g\u1E5Bh\u012Btam||9||</p></div><hr><p>\u0418 <em>(ca)</em> \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>\u2014</p><blockquote><p><strong>[\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0438\u0449\u0435\u0439 <em>(annam)</em>||9||</strong></p></blockquote><p>\u042D\u0442\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435] <em>(tad)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(uktam)</em> \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brvam)</em> [\u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:] &quot;[\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435, \u0438\u043B\u0438 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0435] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u0435\u0441\u0442\u044C] \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25... iti)</em>&quot; \u0432\u043E \u0432\u0442\u043E\u0440\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] \u043F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B <em>(1-2)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0438\u0449\u0435\u0439 Yog\u012B <em>(yogin\u0101m annam)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442\u0441\u044F, [\u0438\u043B\u0438] \u043F\u0440\u043E\u0433\u043B\u0430\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F [\u0438\u043C] <em>(adyam\u0101natv\u0101t grasyam\u0101natv\u0101t)</em><sup>1</sup>|</p><p>[\u042D\u0442\u043E \u0443\u0447\u0435\u043D\u0438\u0435] \u0441\u043E\u0433\u043B\u0430\u0441\u0443\u0435\u0442\u0441\u044F \u0441 \u0442\u0435\u043C <em>(sa\u1E41v\u0101ditam)</em>, \u0447\u0442\u043E <em>(yad)</em> [\u0431\u044B\u043B\u043E] \u043A\u043E\u0433\u0434\u0430-\u0442\u043E <em>(pr\u0101\xF1c)</em> [\u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 Bharga\u015Bikh\u0101]:</p><blockquote><p>&quot;\u0422\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, [\u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u0430\u043A\u043E\u0435 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439,] \u043E\u043D --\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 Yog\u012B-- <em>(sa\u1E25)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442 <em>(kaval\u012B-karoti)</em> \u0432\u0441\u0435 <em>(sarvam)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C \u0441\u043E \u0432\u0441\u0435\u043C--, [\u0431\u0443\u0434\u044C \u0442\u043E] \u0441\u043C\u0435\u0440\u0442\u044C <em>(m\u1E5Btyum)</em> \u0438 <em>(ca... ca)</em> \u0432\u0440\u0435\u043C\u044F --K\u0101la \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u0436\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u043C \u0441\u043C\u0435\u0440\u0442\u044C\u044E-- <em>(k\u0101lam)</em>, \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C <em>(kal\u0101pam)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 <em>(kal\u0101)</em>, \u0446\u0435\u043F\u044C <em>(j\u0101lam)</em> \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 <em>(vik\u0101ra)</em>, \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 <em>(s\u0101tmyam)</em> \u0441\u043E \u0437\u043D\u0430\u043D\u0438\u0435\u043C [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(pratipatti)</em>, \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(j\u0101tam)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vitarka)</em> \u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(aika-\u0101tmya)</em> [\u0438\u043B\u0438] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(n\u0101n\u0101-\u0101tmya... iti)</em>&quot;||</p></blockquote><p>\u0411\u043E\u043B\u0435\u0435 \u0442\u043E\u0433\u043E, [\u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u043C\u044B\u0441\u043B \u0434\u0430\u043D\u043D\u043E\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0432 \u0440\u0430\u043C\u043A\u0430\u0445 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F] <em>(atha ca)</em>: \u042D\u0442\u043E <em>(tad)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0101tmakam)</em> \u0421\u0430\u043C\u043E\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sva-r\u016Bpa-vimar\u015Ba)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0433\u043E <em>(asya)</em> \u043F\u0438\u0449\u0435\u0439 <em>(annam)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443,] \u0432\u044B\u0437\u044B\u0432\u0430\u044F <em>(k\u0101ritay\u0101)</em> \u043F\u043E\u043B\u043D\u043E\u0435 <em>(p\u016Br\u1E47a)</em> \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(parit\u1E5Bpti)</em>, [\u043E\u043D\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(hetu\u1E25)</em> \u043F\u043E\u043A\u043E\u044F <em>(vi\u015Br\u0101nti)</em> \u0432 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0438 \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u0423\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(s\u0101... t\u1E5Bpti\u1E25)</em>, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u043F\u043E\u043B\u043D\u043E\u0442\u0443 <em>(bharit\u0101-k\u0101rit\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(y\u0101)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(utpadyate)</em> \u0438\u0437\u043E \u0434\u043D\u044F \u0432 \u0434\u0435\u043D\u044C <em>(din\u0101t dinam)</em> \u0432 \u0442\u043E\u043C, \u043A\u0442\u043E \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D <em>(sthe)</em><sup>2</sup> \u0432 \u043E\u0434\u043D\u043E\u0439 \u0438\u0437 \u043C\u043D\u043E\u0433\u0438\u0445 <em>(ekatama)</em> Yukti-s, [\u0438\u043B\u0438 Yoga-s] <em>(yukti)</em> \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> --\u0442.\u0435. \u0441\u0440\u0435\u0434\u0438 \u0442\u0435\u0445 \u0442\u0435\u0445\u043D\u0438\u043A \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u044E\u0442\u0441\u044F \u0432 \u044D\u0442\u043E\u043C \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438--, [\u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442] \u0432 \u044D\u0442\u043E\u043C \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 <em>(atra)</em> \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0435 <em>(atyanta)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E <em>(p\u016Br\u1E47at\u0101... iti)</em>&quot;||</p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D] Yukti <em>(yukti\u1E25)</em>, [\u0432 \u0446\u0435\u043B\u043E\u043C,] \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 <em>(r\u016Bp\u0101 eva)</em> \u0432 \u044D\u0442\u043E\u0439 [\u0441\u0442\u0440\u043E\u0444\u0435] <em>(tatra)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em> \u0441\u0442\u0430 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0438 <em>(dv\u0101da\u015Ba-uttara-\u015Bata)</em> \u0441\u0442\u0430\u0434\u0438\u0439, \u0438\u043B\u0438 \u0441\u0442\u0443\u043F\u0435\u043D\u0435\u0439 [\u0432 \u0419\u043E\u0433\u0435] <em>(bh\u016Bmik\u0101)</em>, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 <em>(hi)</em><sup>3</sup>|</p><p>\u042D\u0442\u043E <em>(etad ca)</em> \u0431\u044B\u043B\u043E \u0440\u0435\u0437\u044E\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u044D\u0442\u043E\u043C <em>(anay\u0101)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(k\u0101rikay\u0101)</em>:</p><blockquote><p>&quot;... \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F <em>(sarvad\u0101 ti\u1E63\u1E6Dhet)</em> \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(prabuddha\u1E25)</em>...&quot;||<sup>4</sup><br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 12]</p></blockquote><p>||9||</p><hr><ol><li><p>&quot;\u041F\u043E\u0433\u043B\u043E\u0449\u0430\u0442\u044C/\u043F\u0440\u043E\u0433\u043B\u0430\u0442\u044B\u0432\u0430\u0442\u044C&quot; \u0432 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0422\u0440\u0438\u043A\u0438 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E &quot;\u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E&quot;. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, &quot;\u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0442\u044C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0437\u043D\u0430\u043D\u0438\u044F&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C, \u0447\u0442\u043E \u043E\u043D \u0435\u0441\u0442\u044C \u044D\u0442\u043E&quot;. \u041A\u043E\u0433\u0434\u0430 \u043D\u0435\u0442 &quot;\u0434\u0440\u0443\u0433\u043E\u0433\u043E&quot;, \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u044F\u0449\u0435\u0433\u043E \u0432\u0430\u0441, \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442 \u0438 \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u043C\u0438\u0440. \u042D\u0442\u043E \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0432 \u0447. III, \u0430\u0444. 12 \u0432 Spandak\u0101rik\u0101-s, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440 \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043A \u0434\u0430\u043D\u043D\u043E\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443.</p></li><li><p>K\u1E63emar\u0101ja \u043A\u043E\u0440\u043E\u0442\u043A\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 Vij\xF1\u0101nabhairava:</p></li></ol><p>&quot;\u090F\u0915\u0924\u092E\u092F\u0941\u0915\u094D\u0924\u093F\u0938\u094D\u0925\u0947 \u092F\u094B\u0917\u093F\u0928\u093F \u0907\u0924\u093F \u0936\u0947\u0937\u0903\u0965\u0967\u096A\u096E\u0965&quot; - &quot;Ekatamayuktisthe yogini iti \u015Be\u1E63a\u1E25||148||&quot; \u2014 &quot;\u0412 \u0442\u043E\u043C, \u043A\u0442\u043E \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D \u0432 \u043E\u0434\u043D\u043E\u0439 \u0438\u0437 \u043C\u043D\u043E\u0433\u0438\u0445 Yukti-s, [\u0438\u043B\u0438 Yoga-s], \u0442.\u0435. \u0432 Yog\u012B. \u042D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E [\u0432 \u0441\u0442\u0440\u043E\u0444\u0443, \u0447\u0442\u043E\u0431\u044B \u0437\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435]||148||&quot;</p><ol start="3"><li><p>Vij\xF1\u0101nabhairava \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u0442\u0435\u043C, \u0447\u0442\u043E \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 112 \u0432\u0438\u0434\u043E\u0432 \u0442\u0435\u0445\u043D\u0438\u043A \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438.</p></li><li><p>\u0414\u0430, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u043E\u0439\u0442\u0438 \u0432 \u0447. III, \u0430\u0444. 12 \u0432 Spandak\u0101rik\u0101-s \u0438 \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0432\u0441\u044E \u0441\u0442\u0430\u043D\u0446\u0443. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u044F \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u044E \u0435\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0437\u0434\u0435\u0441\u044C:</p></li></ol><p>&quot;\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0432\u0441\u0435 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0435 \u0441\u0432\u043E\u0435\u043C\u0443 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044E \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C [\u0438] \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0432\u0441\u0435 (\u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435) \u0432 \u043E\u0434\u043D\u0443 \u0442\u043E\u0447\u043A\u0443 --\u0442.\u0435. \u043D\u0430 Spanda--. \u0412\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u044D\u0442\u043E\u0433\u043E, (\u0442\u0430\u043A\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C) \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u0430 \u0434\u0430\u0432\u043B\u0435\u043D\u0438\u044E \u0438 \u043D\u0435 \u0432\u0441\u0442\u0440\u0435\u0432\u043E\u0436\u0435\u043D\u0430 \u0434\u0440\u0443\u0433\u0438\u043C||12||&quot;</p></div>',1),o=[i];function r(s,u,n,k,d,l){return t(),e("div",null,o)}var v=a(p,[["render",r]]);export{q as __pageData,v as default};
